const profile = $json;
const row = $('Read competitors').item.json;
const secUid = profile.data?.user?.sec_uid ?? row.sec_user_id ?? '';

return [{
  json: {
    username: row.username,
    sec_user_id: secUid,
    last_video_id: String(row.last_video_id ?? '').trim(),
  },
}];

const prev = $('Store sec_user_id').item.json;
const postsResponse = $json;
const posts = postsResponse.data?.aweme_list ?? [];
const lastVideoId = prev.last_video_id;
const username = prev.username;

if (!Array.isArray(posts) || posts.length === 0) {
  return [{ json: { username, sec_user_id: prev.sec_user_id, last_video_id: lastVideoId, hasNewPosts: false, newPosts: [], newPostCount: 0 } }];
}

const sorted = [...posts].sort((a, b) => Number(b.create_time ?? 0) - Number(a.create_time ?? 0));
const latestVideoId = String(sorted[0].aweme_id ?? '');

const newPosts = [];
for (const v of sorted) {
  const vid = String(v.aweme_id ?? '');
  if (lastVideoId && vid === lastVideoId) break;
  const s = v.statistics ?? {};
  newPosts.push({
    video_id: vid,
    description: String(v.desc ?? '').substring(0, 200),
    views: Number(s.play_count ?? 0),
    likes: Number(s.digg_count ?? 0),
    comments: Number(s.comment_count ?? 0),
    shares: Number(s.share_count ?? 0),
    link: 'https://www.tiktok.com/@' + username + '/video/' + vid,
  });
}

return [{
  json: {
    username,
    sec_user_id: prev.sec_user_id,
    last_video_id: latestVideoId,
    hasNewPosts: newPosts.length > 0,
    newPosts,
    newPostCount: newPosts.length,
  },
}];

const data = $('Find new posts').item.json;
const now = new Date().toISOString();

return data.newPosts.map(p => ({
  json: {
    username: data.username,
    description: p.description,
    views: p.views,
    likes: p.likes,
    comments: p.comments,
    shares: p.shares,
    link: p.link,
    detected_at: now,
  }
}));

